    function ValidateField_more_buyers_xlsx(&$Campos_Crit, &$Campos_Falta, &$Campos_Erros)
    {
        global $teste_validade;
        $hasError = false;
      if (isset($this->Field_no_validate['more_buyers_xlsx'])) {
          return;
      }
        if ($this->nmgp_opcao != "excluir")
        {
            $sTestFile = $this->more_buyers_xlsx;
            if (!function_exists('sc_upload_unprotect_chars'))
            {
                include_once 'form_clients_steps_renew_mob_doc_name.php';
            }
            $this->more_buyers_xlsx = sc_upload_unprotect_chars($this->more_buyers_xlsx, true);
            $this->more_buyers_xlsx_scfile_name = sc_upload_unprotect_chars($this->more_buyers_xlsx_scfile_name, true);
            if ("" != $this->more_buyers_xlsx && "S" != $this->more_buyers_xlsx_limpa && !$teste_validade->ArqExtensao($this->more_buyers_xlsx, array('xlsx', 'xls')))
            {
                $hasError = true;
                $Campos_Crit .= "Attachment:: " . $this->Ini->Nm_lang['lang_errm_file_invl']; 
                if (!isset($Campos_Erros['more_buyers_xlsx']))
                {
                    $Campos_Erros['more_buyers_xlsx'] = array();
                }
                $Campos_Erros['more_buyers_xlsx'][] = $this->Ini->Nm_lang['lang_errm_file_invl'];
                if (!isset($this->NM_ajax_info['errList']['more_buyers_xlsx']) || !is_array($this->NM_ajax_info['errList']['more_buyers_xlsx']))
                {
                    $this->NM_ajax_info['errList']['more_buyers_xlsx'] = array();
                }
                $this->NM_ajax_info['errList']['more_buyers_xlsx'][] = $this->Ini->Nm_lang['lang_errm_file_invl'];
            }
            if (!$hasError && "" != $this->more_buyers_xlsx && "S" != $this->more_buyers_xlsx_limpa) {
                if (!function_exists('sc_upload_unprotect_chars')) {
                    include_once 'form_clients_steps_renew_mob_doc_name.php';
                }
                $pathParts = pathinfo(sc_upload_unprotect_chars($sTestFile));
                $fileSize = filesize(sc_upload_unprotect_chars($sTestFile));
                $sizeErrorSuffix = '';
                if ('xlsx' == strtolower($pathParts['extension']) && 15728640 < $fileSize) {
                    $sizeErrorSuffix = ' (XLSX < 15 MB)';
                    $hasError = true;
                }
                if ('xls' == strtolower($pathParts['extension']) && 15728640 < $fileSize) {
                    $sizeErrorSuffix = ' (XLS < 15 MB)';
                    $hasError = true;
                }
                if ($hasError) {
                    $Campos_Crit .= "Attachment:: " . $this->Ini->Nm_lang['lang_errm_file_size'] . $sizeErrorSuffix;
                    if (!isset($Campos_Erros['more_buyers_xlsx']))
                    {
                        $Campos_Erros['more_buyers_xlsx'] = array();
                    }
                    $Campos_Erros['more_buyers_xlsx'][] = $this->Ini->Nm_lang['lang_errm_file_size'] . $sizeErrorSuffix;
                    if (!isset($this->NM_ajax_info['errList']['more_buyers_xlsx']) || !is_array($this->NM_ajax_info['errList']['more_buyers_xlsx']))
                    {
                        $this->NM_ajax_info['errList']['more_buyers_xlsx'] = array();
                    }
                    $this->NM_ajax_info['errList']['more_buyers_xlsx'][] = $this->Ini->Nm_lang['lang_errm_file_size'] . $sizeErrorSuffix;
                }
            }
        }
        if ($hasError) {
            global $sc_seq_vert;
            $fieldName = 'more_buyers_xlsx';
            if (isset($sc_seq_vert) && '' != $sc_seq_vert) {
                $fieldName .= $sc_seq_vert;
            }
            $this->NM_ajax_info['fieldsWithErrors'][] = $fieldName;
        }
    } // ValidateField_more_buyers_xlsx

