          //----- main_contact_img_id
   function ajax_return_values_main_contact_img_id($bForce = false)
   {
          if ('navigate_form' == $this->NM_ajax_opcao || 'backup_line' == $this->NM_ajax_opcao || (isset($this->nmgp_refresh_fields) && in_array("main_contact_img_id", $this->nmgp_refresh_fields)) || $bForce)
          {
              $sTmpValue = NM_charset_to_utf8($this->main_contact_img_id);
              $aLookup = array();
   $out_main_contact_img_id = '';
   $out1_main_contact_img_id = '';
   if ('' != $this->main_contact_img_id_ul_name && @is_file($this->Ini->root . $this->Ini->path_imag_temp . '/' . $this->main_contact_img_id_ul_name))
   {
       $this->main_contact_img_id = @file_get_contents($this->Ini->root . $this->Ini->path_imag_temp . '/' . $this->main_contact_img_id_ul_name);
   }
   if ($this->main_contact_img_id != "" && $this->main_contact_img_id != "none")   
   { 
       $out_main_contact_img_id = $this->Ini->path_imag_temp . "/sc_main_contact_img_id_" . $_SESSION['scriptcase']['sc_num_img'] . session_id() . ".gif" ;  
       $out1_main_contact_img_id = $out_main_contact_img_id; 
       $arq_main_contact_img_id = fopen($this->Ini->root . $out_main_contact_img_id, "w") ;  
       if (in_array(strtolower($this->Ini->nm_tpbanco), $this->Ini->nm_bases_access)) 
       { 
           $nm_tmp = nm_conv_img_access(substr($this->main_contact_img_id, 0, 12));
           if (is_string($this->main_contact_img_id) && substr($this->main_contact_img_id, 0, 4) != "*nm*" && is_string($nm_tmp) && substr($nm_tmp, 0, 4) == "*nm*") 
           { 
               $this->main_contact_img_id = nm_conv_img_access($this->main_contact_img_id);
           } 
       } 
       if (is_string($this->main_contact_img_id) && substr($this->main_contact_img_id, 0, 4) == "*nm*") 
       { 
           $this->main_contact_img_id = substr($this->main_contact_img_id, 4) ; 
           $this->main_contact_img_id = base64_decode($this->main_contact_img_id) ; 
       } 
       $img_pos_bm = (is_string($this->main_contact_img_id)) ? strpos($this->main_contact_img_id, "BM") : false; 
       if (!$img_pos_bm === FALSE && $img_pos_bm == 78) 
       { 
           $this->main_contact_img_id = substr($this->main_contact_img_id, $img_pos_bm) ; 
       } 
       fwrite($arq_main_contact_img_id, (string)$this->main_contact_img_id) ;  
       fclose($arq_main_contact_img_id) ;  
       $sc_obj_img = new nm_trata_img($this->Ini->root . $out_main_contact_img_id, true);
       $this->nmgp_return_img['main_contact_img_id'][0] = $sc_obj_img->getHeight();
       $this->nmgp_return_img['main_contact_img_id'][1] = $sc_obj_img->getWidth();
       $_SESSION['scriptcase']['sc_num_img']++ ; 
       $out_main_contact_img_id = $this->Ini->path_imag_temp . "/sc_" . "main_contact_img_id_" . $_SESSION['scriptcase']['sc_num_img'] . session_id() . ".gif" ; 
       $_SESSION['scriptcase']['sc_num_img']++ ; 
       if (!$this->Ini->Gd_missing)
       { 
           $sc_obj_img = new nm_trata_img($this->Ini->root . $out1_main_contact_img_id, true);
           $sc_obj_img->setWidth(50);
           $sc_obj_img->setHeight(50);
           $sc_obj_img->setManterAspecto(true);
           $sc_obj_img->createImg($this->Ini->root . $out_main_contact_img_id);
       } 
       else 
       { 
           $out_main_contact_img_id = $out1_main_contact_img_id;
       } 
       $_SESSION['scriptcase']['sc_num_img']++ ; 
   } 
          $aLookupOrig = $aLookup;
          $this->NM_ajax_info['fldList']['main_contact_img_id'] = array(
                       'row'    => '',
               'type'    => 'imagem',
               'valList' => array($this->Ini->Nm_lang['lang_othr_show_imgg']),
               'imgFile' => $out_main_contact_img_id,
               'imgOrig' => $out1_main_contact_img_id,
               'imgLink' => "javascript:nm_mostra_img(var_ajax_img_main_contact_img_id, '" . $this->nmgp_return_img['main_contact_img_id'][0] . "', '" . $this->nmgp_return_img['main_contact_img_id'][1] . "')",
               'keepImg' => $sKeepImage,
              );
          }
   }

          //----- doc_type
   function ajax_return_values_doc_type($bForce = false)
   {
          if ('navigate_form' == $this->NM_ajax_opcao || 'backup_line' == $this->NM_ajax_opcao || (isset($this->nmgp_refresh_fields) && in_array("doc_type", $this->nmgp_refresh_fields)) || $bForce)
          {
              $sTmpValue = NM_charset_to_utf8($this->doc_type);
              $aLookup = array();
              $this->_tmp_lookup_doc_type = $this->doc_type;

$aLookup[] = array(form_clients_steps_renew_mob_pack_protect_string('Active Secretary of State Registration') => str_replace('<', '&lt;',form_clients_steps_renew_mob_pack_protect_string("Active Secretary of State Registration")));
$aLookup[] = array(form_clients_steps_renew_mob_pack_protect_string('City Business License') => str_replace('<', '&lt;',form_clients_steps_renew_mob_pack_protect_string("City Business License")));
$aLookup[] = array(form_clients_steps_renew_mob_pack_protect_string('Agricultural License') => str_replace('<', '&lt;',form_clients_steps_renew_mob_pack_protect_string("Agricultural License")));
$aLookup[] = array(form_clients_steps_renew_mob_pack_protect_string('Other type of document') => str_replace('<', '&lt;',form_clients_steps_renew_mob_pack_protect_string("Other type of document")));
$_SESSION['sc_session'][$this->Ini->sc_page]['form_clients_steps_renew_mob']['Lookup_doc_type'][] = 'Active Secretary of State Registration';
$_SESSION['sc_session'][$this->Ini->sc_page]['form_clients_steps_renew_mob']['Lookup_doc_type'][] = 'City Business License';
$_SESSION['sc_session'][$this->Ini->sc_page]['form_clients_steps_renew_mob']['Lookup_doc_type'][] = 'Agricultural License';
$_SESSION['sc_session'][$this->Ini->sc_page]['form_clients_steps_renew_mob']['Lookup_doc_type'][] = 'Other type of document';
          $aLookupOrig = $aLookup;
          $sOptComp = "";
          if (isset($this->NM_ajax_info['select_html']['doc_type']) && !empty($this->NM_ajax_info['select_html']['doc_type']))
          {
              $sOptComp = str_replace('{SC_100PERC_CLASS_INPUT}', $this->classes_100perc_fields['input'], $this->NM_ajax_info['select_html']['doc_type']);
          }
          $this->NM_ajax_info['fldList']['doc_type'] = array(
                       'row'    => '',
               'type'    => 'checkbox',
               'switch'  => false,
               'valList' => explode(';', $sTmpValue),
               'colNum'  => 1,
               'optComp'  => $sOptComp,
               'optClass' => 'sc-ui-checkbox-doc_type',
              );
          $aLabel     = array();
          $aLabelTemp = array();
          foreach ($this->NM_ajax_info['fldList']['doc_type']['valList'] as $i => $v)
          {
              $this->NM_ajax_info['fldList']['doc_type']['valList'][$i] = form_clients_steps_renew_mob_pack_protect_string($v);
          }
          foreach ($aLookupOrig as $aValData)
          {
              if (in_array(key($aValData), $this->NM_ajax_info['fldList']['doc_type']['valList']))
              {
                  $aLabelTemp[key($aValData)] = current($aValData);
              }
          }
          foreach ($this->NM_ajax_info['fldList']['doc_type']['valList'] as $iIndex => $sValue)
          {
              $aLabel[$iIndex] = (isset($aLabelTemp[$sValue])) ? $aLabelTemp[$sValue] : $sValue;
          }
          $this->NM_ajax_info['fldList']['doc_type']['labList'] = $aLabel;
          }
   }

          //----- doc_file
   function ajax_return_values_doc_file($bForce = false)
   {
          if ('navigate_form' == $this->NM_ajax_opcao || 'backup_line' == $this->NM_ajax_opcao || (isset($this->nmgp_refresh_fields) && in_array("doc_file", $this->nmgp_refresh_fields)) || $bForce)
          {
              $sTmpValue = NM_charset_to_utf8($this->doc_file);
              $aLookup = array();
              $sTmpExtension = pathinfo($this->doc_file, PATHINFO_EXTENSION);
              $sTmpExtension = null == $sTmpExtension ? '' : '.' . $sTmpExtension;
              $sTmpFile      = 'sc_doc_file_' . md5(mt_rand(1, 1000) . microtime() . session_id()) . $sTmpExtension;
              if (!isset($_SESSION['sc_session'][$this->Ini->sc_page]['form_clients_steps_renew']['download_filenames']))
              {
                  $_SESSION['sc_session'][$this->Ini->sc_page]['form_clients_steps_renew']['download_filenames'] = array();
              }
              $_SESSION['sc_session'][$this->Ini->sc_page]['form_clients_steps_renew']['download_filenames'][$sTmpFile] = $this->doc_file;
              $tmp_file_doc_file = trim(NM_charset_to_utf8($this->doc_file));
              $tmp_icon_doc_file = '';
              if ('' != $tmp_file_doc_file)
              {
                  $tmp_icon_doc_file = $this->gera_icone($tmp_file_doc_file);
              }
          $aLookupOrig = $aLookup;
          $this->NM_ajax_info['fldList']['doc_file'] = array(
                       'row'    => '',
               'type'    => 'documento',
               'valList' => array($sTmpValue),
               'docLink' => "<a href=\"javascript:nm_mostra_doc('0', '" . $sTmpFile . "', 'form_clients_steps_renew')\">" . $tmp_file_doc_file . "</a>",
               'docIcon' => $tmp_icon_doc_file,
               'docReadonly' => "N",
              );
              if ('navigate_form' == $this->NM_ajax_opcao)
              {
                  $this->NM_ajax_info['fldList']['doc_file_salva'] = array(
                      'row'     => '',
                      'type'    => 'text',
                      'valList' => array(''),
                  );
              }
          }
   }

