              $this->xlsx_sample = "";  
              $this->nmgp_dados_form["xlsx_sample"] = $this->xlsx_sample;
              $this->nmgp_dados_form["est_memb_cost"] = $this->est_memb_cost;
              $this->pay = "";  
              $this->nmgp_dados_form["pay"] = $this->pay;
              $this->nmgp_dados_form["addtl_memb_mail"] = $this->addtl_memb_mail;
              $_SESSION['sc_session'][$this->Ini->sc_page]['form_clients_steps_renew_mob']['dados_form'] = $this->nmgp_dados_form;
              $this->formatado = false;
          }
          if (($this->Embutida_form || $this->Embutida_multi) && isset($_SESSION['sc_session'][$this->Ini->sc_page]['form_clients_steps_renew_mob']['foreign_key']) && !empty($_SESSION['sc_session'][$this->Ini->sc_page]['form_clients_steps_renew_mob']['foreign_key']))
          {
              foreach ($_SESSION['sc_session'][$this->Ini->sc_page]['form_clients_steps_renew_mob']['foreign_key'] as $sFKName => $sFKValue)
              {
                   if (isset($this->sc_conv_var[$sFKName]))
                   {
                       $sFKName = $this->sc_conv_var[$sFKName];
                   }
                  eval("\$this->" . $sFKName . " = \"" . $sFKValue . "\";");
              }
          }
      }  
//
//
//-- 
      if ($this->nmgp_opcao != "novo") 
      {
      }
      if (!isset($this->nmgp_refresh_fields)) 
      { 
          $this->nm_proc_onload();
      }
  }
