function members_ct()
{
$_SESSION['scriptcase']['form_clients_steps_renew_mob']['contr_erro'] = 'on';
if (!isset($this->sc_temp_gv_members_ct)) {$this->sc_temp_gv_members_ct = (isset($_SESSION['gv_members_ct'])) ? $_SESSION['gv_members_ct'] : "";}
  
$mc =0;
if ( !empty(trim($this->member1_name )) ) $mc++;
if ( !empty(trim($this->member2_name )) ) $mc++;
if ( !empty(trim($this->member3_name )) ) $mc++;
if ( !empty(trim($this->member4_name )) ) $mc++;
if ( !empty(trim($this->member5_name )) ) $mc++;
if ( !empty(trim($this->member6_name )) ) $mc++;
if ( !empty(trim($this->member7_name )) ) $mc++;
if ( !empty(trim($this->member8_name )) ) $mc++;
if ( !empty(trim($this->member9_name )) ) $mc++;
if ( !empty(trim($this->member10_name )) ) $mc++;
if ( !empty(trim($this->buyers_excel_qty )) ) $mc+= $this->buyers_excel_qty ;
$this->sc_temp_gv_members_ct = $mc;


$sql = "SELECT
  C.bus_cat,
  L.curr_price,
  L.num_of_buyers,
  L.price_after,
  L.pricing_level
FROM bus_categories C
  INNER JOIN members_level L
    ON C.memb_lev_id = L.memb_lev_id
WHERE C.bus_cat_id = " . $this->bus_cat_id ;
 
      $nm_select = $sql; 
      $_SESSION['scriptcase']['sc_sql_ult_comando'] = $nm_select; 
      $_SESSION['scriptcase']['sc_sql_ult_conexao'] = ''; 
      $this->ds = array();
      if ($SCrx = $this->Db->Execute($nm_select)) 
      { 
          $SCy = 0; 
          $nm_count = $SCrx->FieldCount();
          while (!$SCrx->EOF)
          { 
                 for ($SCx = 0; $SCx < $nm_count; $SCx++)
                 { 
                      $this->ds[$SCy] [$SCx] = $SCrx->fields[$SCx];
                 }
                 $SCy++; 
                 $SCrx->MoveNext();
          } 
          $SCrx->Close();
      } 
      elseif (isset($GLOBALS["NM_ERRO_IBASE"]) && $GLOBALS["NM_ERRO_IBASE"] != 1)  
      { 
          $this->ds = false;
          $this->ds_erro = $this->Db->ErrorMsg();
      } 

$bus_cat			= $this->ds[0][0];
$memb_cost			= $this->ds[0][1];
$incl_buyers		= $this->ds[0][2];
$cost_adtl_buyer	= $this->ds[0][3];
$pricing_level		= $this->ds[0][4];

$sql = " SELECT
  SC.bus_subcategory
FROM bus_subcats SC
  INNER JOIN bus_categories C
    ON SC.bus_cat_id = C.bus_cat_id
WHERE SC.bus_subcat_id = " . $this->bus_subcat_id  .
" AND C.bus_cat_id = " . $this->bus_cat_id ;
 
      $nm_select = $sql; 
      $_SESSION['scriptcase']['sc_sql_ult_comando'] = $nm_select; 
      $_SESSION['scriptcase']['sc_sql_ult_conexao'] = ''; 
      $this->ds = array();
      if ($SCrx = $this->Db->Execute($nm_select)) 
      { 
          $SCy = 0; 
          $nm_count = $SCrx->FieldCount();
          while (!$SCrx->EOF)
          { 
                 for ($SCx = 0; $SCx < $nm_count; $SCx++)
                 { 
                      $this->ds[$SCy] [$SCx] = $SCrx->fields[$SCx];
                 }
                 $SCy++; 
                 $SCrx->MoveNext();
          } 
          $SCrx->Close();
      } 
      elseif (isset($GLOBALS["NM_ERRO_IBASE"]) && $GLOBALS["NM_ERRO_IBASE"] != 1)  
      { 
          $this->ds = false;
          $this->ds_erro = $this->Db->ErrorMsg();
      } 

$bus_subcat = $this->ds[0][0];

$memb_est_cost = 0;
switch ( $bus_cat ) {
		
	case "Florist": case "Plant Sales":		
		
		$sql = "SELECT
  					ML.curr_price,
  					ML.price_after,
  					ML.num_of_buyers
				FROM bus_categories C
  					INNER JOIN members_level ML
    					ON C.memb_lev_id = ML.memb_lev_id
				WHERE C.bus_cat = 'Business Services'";
		 
      $nm_select = $sql; 
      $_SESSION['scriptcase']['sc_sql_ult_comando'] = $nm_select; 
      $_SESSION['scriptcase']['sc_sql_ult_conexao'] = ''; 
      $this->ds = array();
      if ($SCrx = $this->Db->Execute($nm_select)) 
      { 
          $SCy = 0; 
          $nm_count = $SCrx->FieldCount();
          while (!$SCrx->EOF)
          { 
                 for ($SCx = 0; $SCx < $nm_count; $SCx++)
                 { 
                      $this->ds[$SCy] [$SCx] = $SCrx->fields[$SCx];
                 }
                 $SCy++; 
                 $SCrx->MoveNext();
          } 
          $SCrx->Close();
      } 
      elseif (isset($GLOBALS["NM_ERRO_IBASE"]) && $GLOBALS["NM_ERRO_IBASE"] != 1)  
      { 
          $this->ds = false;
          $this->ds_erro = $this->Db->ErrorMsg();
      } 

		$memb_cost			= $this->ds[0][0];
		$cost_adtl_buyer	= $this->ds[0][1];
		$incl_buyers		= $this->ds[0][2];
		break;
}

if ( $mc <= 3 ) {
	$memb_est_cost = $memb_cost;
} else {
	$memb_est_cost = $memb_cost + ($cost_adtl_buyer * ($mc - 3));
}
		


$est = "Based on the accurate information provided, the annual membership fee for the<br><b>" . $bus_cat ."</b> (" . $bus_subcat . ") category with <b>" . $mc . "</b> member(s) will be <b>$" . $memb_est_cost . " Per Year.</b><br><small>You will be notified if additional information is required. After the payment, you will receive confirmation along with further details.</small>";

$this->est_memb_cost  = $est;
