    function form_format_readonly($field, $value)
    {
        $result = $value;

        $this->form_highlight_search($result, $field, $value);

        return $result;
    }

    function form_highlight_search(&$result, $field, $value)
    {
        if ($this->proc_fast_search) {
            $this->form_highlight_search_quicksearch($result, $field, $value);
        }
    }

    function form_highlight_search_quicksearch(&$result, $field, $value)
    {
        $searchOk = false;
        if ('SC_all_Cmp' == $this->nmgp_fast_search && in_array($field, array(""))) {
            $searchOk = true;
        }
        elseif ($field == $this->nmgp_fast_search && in_array($field, array("co_name", "client_id", "mailing_address", "appn_date", "city", "bus_cat_id", "state", "bus_subcat_id", "zip_code", "bus_subcat_other", "phone_number", "website_url", "email", "acct_instagram", "acct_facebook", "main_contact_name", "main_contact_phone", "main_contact_email", "main_contact_title", "main_contact_img_id", "doc_type", "doc_file", "appn_note", "member1_name", "member1_phone", "member1_email", "member1_note", "member2_name", "member2_phone", "member2_email", "member2_note", "member3_name", "member3_phone", "member3_email", "member3_note", "member4_name", "member4_phone", "member4_email", "member4_note", "member5_name", "member5_phone", "member5_email", "member5_note", "member6_name", "member6_phone", "member6_email", "member6_note", "member7_name", "member7_phone", "member7_email", "member7_note", "member8_name", "member8_phone", "member8_email", "member8_note", "member9_name", "member9_phone", "member9_email", "member9_note", "member10_name", "member10_phone", "member10_email", "member10_note", "more_buyers_xlsx", "buyers_excel_qty", "applicant_name", "applicant_title", "applicant_signature"))) {
            $searchOk = true;
        }

        if (!$searchOk || '' == $this->nmgp_arg_fast_search) {
            return;
        }

        $htmlIni = '<div class="highlight" style="background-color: #fafaca; display: inline-block">';
        $htmlFim = '</div>';

        if ('qp' == $this->nmgp_cond_fast_search) {
            $keywords = preg_quote($this->nmgp_arg_fast_search, '/');
            $result = preg_replace('/'. $keywords .'/i', $htmlIni . '$0' . $htmlFim, $result);
        } elseif ('eq' == $this->nmgp_cond_fast_search) {
            if (strcasecmp($this->nmgp_arg_fast_search, $value) == 0) {
                $result = $htmlIni. $result .$htmlFim;
            }
        }
    }


