    function wizard_display($template)
    {
        if ($_SESSION['scriptcase']['device_mobile'] && $_SESSION['scriptcase']['display_mobile']) {
            $this->wizard_display_format_wizard('mobile');
        } elseif ('novo' == $this->nmgp_opcao) {
            $this->wizard_display_format_wizard($template);
        } elseif ('page' == $this->wizard_update_mode) {
            $this->wizard_display_format_page();
        } elseif ('pdf' == $this->nmgp_opcao || (isset($_POST['nmgp_opcao']) && 'pdf' == $_POST['nmgp_opcao'])) {
            $this->wizard_display_format_page();
        } else {
            $this->wizard_display_format_wizard($template);
        }
    }

