    function wizard_display_format_wizard($template)
    {
        $this->wizard_display_css_styles();

        switch($template) {
            case 'boxed':
                $this->wizard_display_boxed();
                break;
            case 'lined':
                $this->wizard_display_lined();
                break;
            case 'numbered':
                $this->wizard_display_numbered();
                break;
            case 'mobile':
                $this->wizard_display_mobile();
                break;
            case 'basic':
            default:
                $this->wizard_display_basic();
                break;
        }
    }

