    function wizard_display_getControlClass($stepNo)
    {
        if ($stepNo < $_SESSION['sc_session'][$this->Ini->sc_page]['form_clients_steps_renew_mob']['form_wizard']['actual_step']) {
            return 'sc-ui-form-step-done';
        } elseif ($stepNo == $_SESSION['sc_session'][$this->Ini->sc_page]['form_clients_steps_renew_mob']['form_wizard']['actual_step']) {
            return 'sc-ui-form-step-now';
        } elseif ($stepNo == $_SESSION['sc_session'][$this->Ini->sc_page]['form_clients_steps_renew_mob']['form_wizard']['actual_step'] + 1) {
            return 'sc-ui-form-step-next';
        } elseif ('novo' == $this->nmgp_opcao) {
            return 'sc-ui-form-step-todo';
        } else {
            return 'sc-ui-form-step-next';
        }
    }

function nmgp_redireciona($tipo=0)
{
   global $nm_apl_dependente;
   if (isset($_SESSION['scriptcase']['nm_sc_retorno']) && !empty($_SESSION['scriptcase']['nm_sc_retorno']) && $_SESSION['scriptcase']['sc_tp_saida'] != "D" && $nm_apl_dependente != 1) 
   {
       $nmgp_saida_form = $_SESSION['scriptcase']['nm_sc_retorno'];
   }
