    function getButtonIds($buttonName) {
        switch ($buttonName) {
            case "new":
                return array("sc_b_new_b.sc-unique-btn-1");
                break;
            case "insert":
                return array("sc_b_ins_b.sc-unique-btn-2");
                break;
            case "update":
                return array("sc_b_upd_b.sc-unique-btn-3");
                break;
            case "bstepretorna":
                return array("sc_b_stepret_b.sc-unique-btn-4");
                break;
            case "bstepavanca":
                return array("sc_b_stepavc_b.sc-unique-btn-5");
                break;
            case "pdf_download":
                return array("sc_pdf_download_bot");
                break;
            case "breload":
                return array("sc_b_reload_b.sc-unique-btn-6");
                break;
            case "btn_exit_app":
                return array("sc_btn_exit_app_bot");
                break;
            case "exit":
                return array("sc_b_sai_b.sc-unique-btn-7", "sc_b_sai_b.sc-unique-btn-12");
                break;
            case "first":
                return array("sc_b_ini_b.sc-unique-btn-8");
                break;
            case "back":
                return array("sc_b_ret_b.sc-unique-btn-9");
                break;
            case "forward":
                return array("sc_b_avc_b.sc-unique-btn-10");
                break;
            case "last":
                return array("sc_b_fim_b.sc-unique-btn-11");
                break;
        }

        return array($buttonName);
    } // getButtonIds

